<?php/** * Helper functions for AquaLuxe theme * * @package AquaLuxe * @since 1.0.0 */// Exit if accessed directlyif (!defined('ABSPATH')) {    exit;}/** * Get theme option * * @param string $option Option name * @param mixed $default Default value * @return mixed */function aqualuxe_get_option($option, $default = '') {    $options = get_option('aqualuxe_options');    return isset($options[$option]) ? $options[$option] : $default;}/** * Get theme mod with default * * @param string $name Theme mod name * @param mixed $default Default value * @return mixed */function aqualuxe_get_theme_mod($name, $default = '') {    return get_theme_mod($name, $default);}/** * Get asset URL * * @param string $path Asset path * @return string */function aqualuxe_asset($path) {    if (file_exists(AQUALUXE_DIR . '/assets/dist/' . $path)) {        return AQUALUXE_URI . '/assets/dist/' . $path;    }        return AQUALUXE_URI . '/assets/' . $path;}/** * Get image URL * * @param string $image Image name * @return string */function aqualuxe_image($image) {    return aqualuxe_asset('images/' . $image);}/** * Check if dark mode is enabled * * @return bool */function aqualuxe_is_dark_mode() {    // Check user preference first    if (isset($_COOKIE['aqualuxe_dark_mode'])) {        return $_COOKIE['aqualuxe_dark_mode'] === 'true';    }        // Check theme default    return aqualuxe_get_option('default_dark_mode', false);}/** * Get current language * * @return string */function aqualuxe_get_current_language() {    // WPML    if (defined('ICL_LANGUAGE_CODE')) {        return ICL_LANGUAGE_CODE;    }        // Polylang    if (function_exists('pll_current_language')) {        return pll_current_language();    }        // Default    return get_locale();}/** * Get available languages * * @return array */function aqualuxe_get_languages() {    $languages = [];        // WPML    if (function_exists('icl_get_languages')) {        $wpml_languages = icl_get_languages('skip_missing=0');                if (!empty($wpml_languages)) {            foreach ($wpml_languages as $lang) {                $languages[] = [                    'code' => $lang['code'],                    'name' => $lang['native_name'],                    'url' => $lang['url'],                    'flag' => $lang['country_flag_url'],                    'active' => $lang['active'],                ];            }        }    }        // Polylang    elseif (function_exists('pll_languages_list')) {        $pll_languages = pll_languages_list(['fields' => '']);                if (!empty($pll_languages)) {            foreach ($pll_languages as $lang) {                $languages[] = [                    'code' => $lang->slug,                    'name' => $lang->name,                    'url' => $lang->home_url,                    'flag' => $lang->flag_url,                    'active' => $lang->slug === pll_current_language(),                ];            }        }    }        // Default    if (empty($languages)) {        $languages[] = [            'code' => get_locale(),            'name' => get_locale(),            'url' => home_url(),            'flag' => '',            'active' => true,        ];    }        return $languages;}/** * Get post thumbnail with fallback * * @param int $post_id Post ID * @param string $size Image size * @return string */function aqualuxe_get_post_thumbnail($post_id = null, $size = 'post-thumbnail') {    if (null === $post_id) {        $post_id = get_the_ID();    }        if (has_post_thumbnail($post_id)) {        return get_the_post_thumbnail_url($post_id, $size);    }        // Return default image    return aqualuxe_image('placeholder.jpg');}/** * Get excerpt with custom length * * @param int $length Excerpt length * @param int $post_id Post ID * @return string */function aqualuxe_excerpt($length = 55, $post_id = null) {    if (null === $post_id) {        $post_id = get_the_ID();    }        $post = get_post($post_id);        if (empty($post)) {        return '';    }        if (has_excerpt($post_id)) {        return get_the_excerpt($post_id);    }        $content = get_the_content('', false, $post_id);    $content = strip_shortcodes($content);    $content = excerpt_remove_blocks($content);    $content = apply_filters('the_content', $content);    $content = str_replace(']]>', ']]&gt;', $content);        return wp_trim_words($content, $length, '...');}/** * Get social media links * * @return array */function aqualuxe_get_social_links() {    $social_links = [];        $networks = [        'facebook' => [            'label' => __('Facebook', 'aqualuxe'),            'icon' => 'fab fa-facebook-f',        ],        'twitter' => [            'label' => __('Twitter', 'aqualuxe'),            'icon' => 'fab fa-twitter',        ],        'instagram' => [            'label' => __('Instagram', 'aqualuxe'),            'icon' => 'fab fa-instagram',        ],        'youtube' => [            'label' => __('YouTube', 'aqualuxe'),            'icon' => 'fab fa-youtube',        ],        'linkedin' => [            'label' => __('LinkedIn', 'aqualuxe'),            'icon' => 'fab fa-linkedin-in',        ],        'pinterest' => [            'label' => __('Pinterest', 'aqualuxe'),            'icon' => 'fab fa-pinterest-p',        ],    ];        foreach ($networks as $network => $data) {        $url = aqualuxe_get_option($network . '_url');                if (!empty($url)) {            $social_links[$network] = [                'url' => $url,                'label' => $data['label'],                'icon' => $data['icon'],            ];        }    }        return $social_links;}/** * Get contact information * * @return array */function aqualuxe_get_contact_info() {    return [        'address' => aqualuxe_get_option('address'),        'phone' => aqualuxe_get_option('phone'),        'email' => aqualuxe_get_option('email'),        'hours' => aqualuxe_get_option('hours'),    ];}/** * Check if WooCommerce is active * * @return bool */function aqualuxe_is_woocommerce_active() {    return class_exists('WooCommerce');}/** * Get currency symbol * * @return string */function aqualuxe_get_currency_symbol() {    if (aqualuxe_is_woocommerce_active()) {        return get_woocommerce_currency_symbol();    }        return '$';}/** * Format price * * @param float $price Price * @return string */function aqualuxe_format_price($price) {    if (aqualuxe_is_woocommerce_active()) {        return wc_price($price);    }        return aqualuxe_get_currency_symbol() . number_format($price, 2);}/** * Get wishlist items * * @return array */function aqualuxe_get_wishlist_items() {    if (!is_user_logged_in()) {        return [];    }        $user_id = get_current_user_id();    $wishlist = get_user_meta($user_id, 'aqualuxe_wishlist', true);        if (!is_array($wishlist)) {        $wishlist = [];    }        return $wishlist;}/** * Check if product is in wishlist * * @param int $product_id Product ID * @return bool */function aqualuxe_is_in_wishlist($product_id) {    $wishlist = aqualuxe_get_wishlist_items();    return in_array($product_id, $wishlist);}/** * Add product to wishlist * * @param int $product_id Product ID * @return bool */function aqualuxe_add_to_wishlist($product_id) {    if (!is_user_logged_in()) {        return false;    }        $user_id = get_current_user_id();    $wishlist = aqualuxe_get_wishlist_items();        if (!in_array($product_id, $wishlist)) {        $wishlist[] = $product_id;        update_user_meta($user_id, 'aqualuxe_wishlist', $wishlist);    }        return true;}/** * Remove product from wishlist * * @param int $product_id Product ID * @return bool */function aqualuxe_remove_from_wishlist($product_id) {    if (!is_user_logged_in()) {        return false;    }        $user_id = get_current_user_id();    $wishlist = aqualuxe_get_wishlist_items();        if (in_array($product_id, $wishlist)) {        $wishlist = array_diff($wishlist, [$product_id]);        update_user_meta($user_id, 'aqualuxe_wishlist', $wishlist);    }        return true;}/** * Get wishlist count * * @return int */function aqualuxe_get_wishlist_count() {    $wishlist = aqualuxe_get_wishlist_items();    return count($wishlist);}/** * Get cart URL * * @return string */function aqualuxe_get_cart_url() {    if (aqualuxe_is_woocommerce_active()) {        return wc_get_cart_url();    }        return home_url();}/** * Get cart count * * @return int */function aqualuxe_get_cart_count() {    if (aqualuxe_is_woocommerce_active()) {        return WC()->cart ? WC()->cart->get_cart_contents_count() : 0;    }        return 0;}/** * Get account URL * * @return string */function aqualuxe_get_account_url() {    if (aqualuxe_is_woocommerce_active()) {        return wc_get_account_endpoint_url('dashboard');    }        return home_url();}/** * Get shop URL * * @return string */function aqualuxe_get_shop_url() {    if (aqualuxe_is_woocommerce_active()) {        return wc_get_page_permalink('shop');    }        return home_url();}/** * Get checkout URL * * @return string */function aqualuxe_get_checkout_url() {    if (aqualuxe_is_woocommerce_active()) {        return wc_get_checkout_url();    }        return home_url();}/** * Get product categories * * @param array $args Query args * @return array */function aqualuxe_get_product_categories($args = []) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $defaults = [        'taxonomy' => 'product_cat',        'hide_empty' => true,        'orderby' => 'name',        'order' => 'ASC',    ];        $args = wp_parse_args($args, $defaults);        return get_terms($args);}/** * Get featured products * * @param int $limit Number of products * @return array */function aqualuxe_get_featured_products($limit = 4) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $args = [        'post_type' => 'product',        'posts_per_page' => $limit,        'tax_query' => [            [                'taxonomy' => 'product_visibility',                'field' => 'name',                'terms' => 'featured',                'operator' => 'IN',            ],        ],    ];        return get_posts($args);}/** * Get sale products * * @param int $limit Number of products * @return array */function aqualuxe_get_sale_products($limit = 4) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $args = [        'post_type' => 'product',        'posts_per_page' => $limit,        'meta_query' => [            'relation' => 'OR',            [                'key' => '_sale_price',                'value' => '',                'compare' => '!=',            ],            [                'key' => '_min_variation_sale_price',                'value' => '',                'compare' => '!=',            ],        ],    ];        return get_posts($args);}/** * Get best selling products * * @param int $limit Number of products * @return array */function aqualuxe_get_best_selling_products($limit = 4) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $args = [        'post_type' => 'product',        'posts_per_page' => $limit,        'meta_key' => 'total_sales',        'orderby' => 'meta_value_num',        'order' => 'DESC',    ];        return get_posts($args);}/** * Get related products * * @param int $product_id Product ID * @param int $limit Number of products * @return array */function aqualuxe_get_related_products($product_id, $limit = 4) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $product = wc_get_product($product_id);        if (!$product) {        return [];    }        $related_products = wc_get_related_products($product_id, $limit);        if (empty($related_products)) {        return [];    }        $args = [        'post_type' => 'product',        'post__in' => $related_products,        'posts_per_page' => $limit,    ];        return get_posts($args);}/** * Get product reviews * * @param int $product_id Product ID * @param int $limit Number of reviews * @return array */function aqualuxe_get_product_reviews($product_id, $limit = 5) {    $args = [        'post_id' => $product_id,        'status' => 'approve',        'number' => $limit,        'type' => 'review',    ];        return get_comments($args);}/** * Get product rating * * @param int $product_id Product ID * @return float */function aqualuxe_get_product_rating($product_id) {    if (!aqualuxe_is_woocommerce_active()) {        return 0;    }        $product = wc_get_product($product_id);        if (!$product) {        return 0;    }        return $product->get_average_rating();}/** * Get product price * * @param int $product_id Product ID * @return string */function aqualuxe_get_product_price($product_id) {    if (!aqualuxe_is_woocommerce_active()) {        return '';    }        $product = wc_get_product($product_id);        if (!$product) {        return '';    }        return $product->get_price_html();}/** * Get product stock status * * @param int $product_id Product ID * @return string */function aqualuxe_get_product_stock_status($product_id) {    if (!aqualuxe_is_woocommerce_active()) {        return '';    }        $product = wc_get_product($product_id);        if (!$product) {        return '';    }        return $product->get_stock_status();}/** * Get product gallery images * * @param int $product_id Product ID * @return array */function aqualuxe_get_product_gallery_images($product_id) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $product = wc_get_product($product_id);        if (!$product) {        return [];    }        $attachment_ids = $product->get_gallery_image_ids();    $images = [];        if ($product->get_image_id()) {        $images[] = [            'id' => $product->get_image_id(),            'url' => wp_get_attachment_url($product->get_image_id()),            'alt' => get_post_meta($product->get_image_id(), '_wp_attachment_image_alt', true),        ];    }        foreach ($attachment_ids as $attachment_id) {        $images[] = [            'id' => $attachment_id,            'url' => wp_get_attachment_url($attachment_id),            'alt' => get_post_meta($attachment_id, '_wp_attachment_image_alt', true),        ];    }        return $images;}/** * Get product attributes * * @param int $product_id Product ID * @return array */function aqualuxe_get_product_attributes($product_id) {    if (!aqualuxe_is_woocommerce_active()) {        return [];    }        $product = wc_get_product($product_id);        if (!$product) {        return [];    }        $attributes = [];        if ($product->get_attributes()) {        foreach ($product->get_attributes() as $attribute) {            if ($attribute->get_visible()) {                $name = $attribute->get_name();                $values = [];                                if ($attribute->is_taxonomy()) {                    $terms = wp_get_post_terms($product_id, $name, ['fields' => 'names']);                    $values = $terms;                } else {                    $values = $attribute->get_options();                }                                $attributes[$name] = [                    'name' => wc_attribute_label($name),                    'values' => $values,                ];            }        }    }        return $attributes;}